import { cn } from "@portugal/ui-lib";
import type { LatLngExpression } from "leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import { useEffect, useRef, useState } from "react";
import {
	CircleMarker,
	MapContainer,
	TileLayer,
	Tooltip,
	useMap,
} from "react-leaflet";

export type PlotLocationMapTileLayerConfig = {
	url: string;
	attribution: string;
};

export type PlotLocationMapProps = {
	lat: number;
	lng: number;
	/** Correlates map transitions when the selected plot changes (even if coords were equal). */
	plotId: string;
	zoom?: number;
	/** Seconds for `flyTo` when panning/zooming to a new plot position (after initial paint). */
	flyToDurationSeconds?: number;
	markerRadius?: number;
	markerLabel?: string;
	tileLayer?: PlotLocationMapTileLayerConfig;
	className?: string;
};

const defaultTileLayer: PlotLocationMapTileLayerConfig = {
	url: "https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png",
	attribution:
		'&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
};

const defaultMarker = {
	color: "#047857",
	weight: 2,
	fillColor: "#34d399",
	fillOpacity: 0.9,
} as const;

function FlyToPlotPosition({
	lat,
	lng,
	zoom,
	plotId,
	flyToDurationSeconds,
}: {
	lat: number;
	lng: number;
	zoom: number;
	plotId: string;
	flyToDurationSeconds: number;
}) {
	const map = useMap();
	const initialPaint = useRef(true);

	useEffect(() => {
		if (initialPaint.current) {
			map.setView([lat, lng], zoom, { animate: false });
			initialPaint.current = false;
			return;
		}
		map.flyTo([lat, lng], zoom, { duration: flyToDurationSeconds });
	}, [lat, lng, zoom, plotId, map, flyToDurationSeconds]);

	return null;
}

/** Re-fit tiles when the map container is resized (e.g. flex layout or panel width changes). */
function MapResizeSync() {
	const map = useMap();
	useEffect(() => {
		const run = () => map.invalidateSize({ animate: false });
		const id = requestAnimationFrame(run);
		const el = map.getContainer();
		const ro = new ResizeObserver(run);
		ro.observe(el);
		return () => {
			cancelAnimationFrame(id);
			ro.disconnect();
		};
	}, [map]);
	return null;
}

export function PlotLocationMap({
	lat,
	lng,
	plotId,
	zoom = 14,
	flyToDurationSeconds = 1.25,
	markerRadius = 11,
	markerLabel,
	tileLayer = defaultTileLayer,
	className,
}: PlotLocationMapProps) {
	const [mounted, setMounted] = useState(false);
	const center: LatLngExpression = [lat, lng];

	useEffect(() => {
		setMounted(true);
	}, []);

	if (!mounted) {
		return (
			<div
				className={cn(
					"flex aspect-video w-full items-center justify-center rounded-xl bg-muted/40 text-xs text-muted-foreground ring-1 ring-border/30",
					className,
				)}
			>
				Loading map…
			</div>
		);
	}

	return (
		<div
			className={cn(
				"relative aspect-video w-full overflow-hidden rounded-xl ring-1 ring-border/30",
				className,
			)}
		>
			<MapContainer
				center={center}
				zoom={zoom}
				className="relative z-0 h-full w-full [&_.leaflet-container]:h-full [&_.leaflet-container]:w-full [&_.leaflet-container]:bg-muted/30 [&_.leaflet-control-attribution]:text-[10px]"
				scrollWheelZoom
				style={{ height: "100%", width: "100%" }}
			>
				<TileLayer attribution={tileLayer.attribution} url={tileLayer.url} />
				<FlyToPlotPosition
					lat={lat}
					lng={lng}
					zoom={zoom}
					plotId={plotId}
					flyToDurationSeconds={flyToDurationSeconds}
				/>
				<MapResizeSync />
				<CircleMarker center={center} radius={markerRadius} pathOptions={{ ...defaultMarker }}>
					{markerLabel ? (
						<Tooltip direction="top" offset={[0, -6]} opacity={1}>
							<span className="text-xs font-medium">{markerLabel}</span>
						</Tooltip>
					) : null}
				</CircleMarker>
			</MapContainer>
		</div>
	);
}

