import { cn } from "@portugal/ui-lib";
import type { ComponentType } from "react";
import { useEffect, useState } from "react";

import type { PlotLocationMapProps } from "./plot-location-map";

/**
 * Loads Leaflet only in the browser via dynamic import so SSR never evaluates `leaflet` (it touches `window` at import time).
 */
export function PlotLocationMapClient(props: PlotLocationMapProps) {
	const [Map, setMap] = useState<ComponentType<PlotLocationMapProps> | null>(
		null,
	);

	useEffect(() => {
		let cancelled = false;
		void import("./plot-location-map").then((mod) => {
			if (!cancelled) {
				setMap(() => mod.PlotLocationMap);
			}
		});
		return () => {
			cancelled = true;
		};
	}, []);

	if (!Map) {
		return (
			<div
				className={cn(
					"flex aspect-video w-full items-center justify-center rounded-xl bg-muted/40 text-xs text-muted-foreground ring-1 ring-border/30",
					props.className,
				)}
			>
				Loading map…
			</div>
		);
	}

	return <Map {...props} />;
}

